  function_name = "insecure-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"

  environment {
    variables = {
      password    = "hardcoded_password_value"
      db_secret   = "my_database_secret_1234"
      api_token   = "hardcoded_api_token_abc"
    }
  }
}

resource "aws_security_group" "egress_only_https" {
  name = "egress-only-https"
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "web_server" {
  name = "web-server"
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_policy" "ec2_describe" {
  name = "ec2-describe-only"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["ec2:DescribeInstances", "ec2:DescribeSecurityGroups"]
      Resource = "arn:aws:ec2:us-east-1:123456789012:instance/*"
    }]
  })
}

resource "aws_s3_bucket" "logs_bucket" {
  bucket = "app-logs-bucket"
}

resource "aws_security_group" "open_ssh" {
  name = "open-ssh"
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_policy" "ec2_s3_all" {
  name = "ec2-s3-all"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["ec2:*", "s3:*"]
      Resource = "*"
    }]
  })
}

resource "aws_iam_policy" "s3_read_all" {
  name = "s3-read-all"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["s3:GetObject", "s3:ListBucket"]
      Resource = "*"
    }]
  })
}

resource "aws_cloudtrail" "disabled_trail" {
  name                       = "disabled-trail"
  s3_bucket_name             = aws_s3_bucket.trail.id
  enable_logging             = false
  enable_log_file_validation = false
}

resource "aws_s3_bucket" "secure_bucket" {
